async function dual_upload({ text, bucketId, folderId, fileName }, userSettings) {
  const oauthToken = '{OAUTH_PLUGIN_ACCESS_TOKEN}';
  if (!userSettings.token || oauthToken === '') {
    return 'ERROR: Please set MemoryPlugin auth token and ensure Google Drive OAuth is connected.';
  }

  const MP_API = 'https://www.memoryplugin.com/api/';

  const today = new Date();
  let memoryText = text;
  if (today.getFullYear() > 2023 && !text.match(/^\d{4}-\d{2}-\d{2}/)) {
    const dateStr = today.toISOString().split('T')[0];
    memoryText = dateStr + '\n\n' + text;
  }

  const memoryBody = { text: memoryText };
  if (bucketId) memoryBody.bucketId = bucketId;

  const memoryPromise = fetch(MP_API + 'v2/memory?client=typingmind', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + userSettings.token,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(memoryBody)
  }).then(async res => {
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error('Error storing memory: ' + (err.error || res.statusText));
    }
    return res.json();
  });

  const finalFileName = fileName || 'Untitled.md';
  const metadata = {
    name: finalFileName,
    mimeType: 'text/markdown'
  };
  if (folderId) {
    metadata.parents = [folderId];
  }

  const boundary = '-------314159265358979323846';
  const delimiter = "\r\n--" + boundary + "\r\n";
  const close_delim = "\r\n--" + boundary + "--";

  const multipartRequestBody = 
    delimiter +
    'Content-Type: application/json\r\n\r\n' +
    JSON.stringify(metadata) +
    delimiter +
    'Content-Type: text/markdown\r\n\r\n' +
    text +
    close_delim;

  const drivePromise = fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + oauthToken,
      'Content-Type': 'multipart/related; boundary=' + boundary
    },
    body: multipartRequestBody
  }).then(async res => {
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error('Error uploading to Drive: ' + (err.error && err.error.message ? err.error.message : res.statusText));
    }
    return res.json();
  });

  try {
    const [memoryRes, driveRes] = await Promise.all([memoryPromise, drivePromise]);
    const memoryMsg = memoryRes.isDuplicate ? 'Duplicate memory (already exists)' : 'Memory stored successfully';
    return `Success!\n- Memory: ${memoryMsg}\n- Drive: File "${finalFileName}" uploaded successfully.`;
  } catch (error) {
    return `Upload Failed: ${error.message}`;
  }
}
